import { useEffect, useState } from "react";
import { auth, db } from "./firebase";
import { onAuthStateChanged } from "firebase/auth";
import { doc, getDoc } from "firebase/firestore";

import Login from "./pages/Login";
import Register from "./pages/Register";
import CustomerDashboard from "./pages/CustomerDashboard";
import AgentDashboard from "./pages/AgentDashboard";

function App() {
  const [user, setUser] = useState(null);
  const [role, setRole] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showRegister, setShowRegister] = useState(false);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      if (currentUser) {
        setUser(currentUser);

        const docRef = doc(db, "users", currentUser.uid);
        const docSnap = await getDoc(docRef);

        if (docSnap.exists()) {
          setRole(docSnap.data().role);
        } else {
          setRole(null);
        }
      } else {
        setUser(null);
        setRole(null);
      }

      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  if (loading) return <h2>Loading...</h2>;

  // 🔹 If NOT logged in → show Login or Register
  if (!user) {
    if (showRegister) {
      return <Register goToLogin={() => setShowRegister(false)} />;
    }
    return <Login goToRegister={() => setShowRegister(true)} />;
  }

  // 🔹 If logged in but no role
  if (!role) {
    return <h2>No role assigned. Contact Admin.</h2>;
  }

  // 🔹 Based on role
  if (role === "customer") return <CustomerDashboard />;
  if (role === "agent") return <AgentDashboard />;

  return <h2>Invalid role</h2>;
}

export default App;
